The auto-fight setInterval in useCombat.js needs to clear when the tab is hidden and restart when it becomes visible.
  Without this, all the queued combat state updates fire at once on tab focus causing a 25 second main thread freeze.

  Fix the visibilitychange handler to also pause on hide:

  const handleVisibility = () => {
    if (document.hidden) {
      if (autoFightInterval.current) {
        clearInterval(autoFightInterval.current);
        autoFightInterval.current = null;
      }
    } else if (isAutoFightingRef.current && restartIntervalRef.current) {
      restartIntervalRef.current();
    }
  };
